private bool IsValidTargetSelected(MinionCardDisplayer minion, HeroDisplayer hero)
{
    return (minion != null && (cardObject.IsNeedSelectOppositeMinion() || cardObject.IsNeedSelectOwnSideMinion())) ||
           (hero != null && (cardObject.IsNeedSelectOppositeHero() || cardObject.IsNeedSelectOwnSideHero()));
}

private void ProcessSelectedTargets(MinionCardDisplayer minion, HeroDisplayer hero)
{
    List<Effect> targetedEffects = cardObject.GetCardAllSelectedTargetEffects();
    foreach (var effect in targetedEffects)
    {
        foreach (var triggerEffect in effect.triggerEffects)
        {
            HandleTriggerEffect(triggerEffect, minion, hero);
        }
    }
}

