protected virtual void OnDrag()
{
    if (GameMode.GetIsInCounterPhase())
    {
        CardTypes cardType = cardObject.GetCardType();
        Player ownerPlayer = cardObject.GetOwnerPlayer();

        // 计数器阶段仅限英雄卡牌处理
        if (cardType == CardTypes.MinionCard)
        {
            GameMode.OnPlayerCounterMinionCardWarning?.Invoke();
            return;
        }

        // 如果是陷阱卡片并且在手牌中，触发警告
        if (cardType == CardTypes.TrapCard && IsInHand)
        {
            GameMode.OnPlayerCounterTrapCardWarning?.Invoke();
            return;
        }

        // 如果不是回合玩家，对于陷阱卡牌或法术卡片触发回合警告
        if ((cardType == CardTypes.TrapCard && IsInTrapfield) || 
            cardType == CardTypes.MagicCard && 
            !GameMode.IsCounterPhasePlayerTurn(ownerPlayer))
        {
            GameMode.OnPlayerTurnWarning?.Invoke();
            return;
        }
    }

    // 如果不是计数器阶段或者没有触发任何警告，则不显示提示
    cardTooltip.Set(false);
}
