    List<TriggerEffect> triggerEffects = effect.triggerEffects;
    Card cardObject = gameMode.GetActorObject(triggerCard);
    Player player = gameMode.GetActorObject(cardObject.GetOwnerPlayer());
    Hero cardHero = gameMode.GetActorObject(player.GetHero());
    foreach (var triggerEffect in triggerEffects)
    { 
        // 抽牌效果或者如果是全场则是作为攻击者
        if (!cardObject.IsNeedChooseTriggerEffect(triggerEffect))
        {
            if (triggerEffect.luaPath.Contains("All"))
            {
                triggerEffect.targetValue += cardHero.GetSpellPowerValue();
            }
            PrepareLuaSingleParam(gameMode, triggerEffect, cardObject, luaParams);
            continue;
        }

        foreach (var targetCard in targetCards)
        {
            // 计算上法强的值
            if (triggerEffect.luaPath.Contains("Damage"))
            {
                triggerEffect.targetValue += cardHero.GetSpellPowerValue();
            }

            Card targetCardObject = gameMode.GetActorObject(targetCard);
            if (triggerEffect.luaPath.Contains("Damage"))
            {
                if (targetCardObject.HasEffect(CardKeyWordType.HolyShield))
                {
                    targetCardObject.SetPreviewData	(0);
                }
                else
                {
                    targetCardObject.SetPreviewData(-triggerEffect.targetValue);
                }
            }
            else if (triggerEffect.luaPath.Contains("Heal"))
            {
                targetCardObject.SetPreviewData(triggerEffect.targetValue);
            }
        }

        foreach (var targetHero in targetHeroes)
        {
            // 计算上法强的值
            if (triggerEffect.luaPath.Contains("Damage"))
            {
                triggerEffect.targetValue += cardHero.GetSpellPowerValue();
            }

            Hero targetHeroObject = gameMode.GetActorObject(targetHero);

            if (triggerEffect.luaPath.Contains("Damage"))
            {
                targetHeroObject.SetPreviewData(-triggerEffect.targetValue);
